parameters.functionCode:
let content = '';
try {
  if ($json.choices && $json.choices.length > 0) {
    content = $json.choices[0].message.content;
  } else {
    const errInfo = $json.error ? $json.error.message : JSON.stringify($json);
    return { error: 'Groq API Error: ' + errInfo, raw: JSON.stringify($json) };
  }
} catch (e) {
  return { error: 'Failed to access Groq Node data: ' + e.message, raw: JSON.stringify($json) };
}

try {
  const start = content.indexOf('{');
  if (start === -1) return { error: 'No JSON object found', raw: content };

  let count = 0;
  let end = -1;
  for (let i = start; i < content.length; i++) {
    if (content[i] === '{') count++;
    if (content[i] === '}') count--;
    if (count === 0) {
      end = i;
      break;
    }
  }

  if (end === -1) end = content.lastIndexOf('}');
  const jsonStr = content.substring(start, end + 1);

  return JSON.parse(jsonStr);
} catch (e) {
  return { error: 'Parsing failed: ' + e.message, raw: content };
}
